// Combine for total 100 articles
export const allArticles = [...articles, ...articleStubs]

// Get article by slug
export function getArticle(slug) {
  return articles.find(a => a.slug === slug) || articleStubs.find(a => a.slug === slug) || null
}

// Get articles by category
export function getArticlesByCategory(category, limit = null) {
  const filtered = allArticles.filter(a => a.category === category)
  return limit ? filtered.slice(0, limit) : filtered
}

// Get featured articles
export function getFeaturedArticles(limit = 6) {
  return articles.filter(a => a.featured).slice(0, limit)
}

// Get latest articles
export function getLatestArticles(limit = 12) {
  return allArticles.slice(0, limit)
}

// Check if article has full content
export function hasFullContent(slug) {
  return articles.some(a => a.slug === slug)
}
